window.docContents[42].resolve({"/Section-References/#sec-ref":{"contents":"Sections with tags can be cross-referenced.\nThey additionally gain permalink indicators that can be used to link to them even if the document is reorganized.\nTags are added in section metadata, e.g.\n\n%%%\ntag := \"my-tag\"\n%%%\n\n\nThey can be linked to using ref.\nHere's one to this section.\n\n","context":"Zippers: A Documentation Example","header":"5. Section References","id":"/Section-References/#sec-ref"}});